from flask import Flask, request, jsonify, session
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import os
import pyotp

app = Flask(__name__)
app.secret_key = os.urandom(24)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(128), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(16), nullable=True)

db.create_all()

@app.route('/register', methods=['POST'])
def register():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    mfa_enabled = data.get('mfa_enabled', False)

    if User.query.filter_by(username=username).first():
        return jsonify({'message': 'User already exists'}), 400

    hashed_password = generate_password_hash(password)
    mfa_secret = pyotp.random_base32() if mfa_enabled else None
    new_user = User(username=username, password=hashed_password, mfa_enabled=mfa_enabled, mfa_secret=mfa_secret)
    db.session.add(new_user)
    db.session.commit()
    
    return jsonify({'message': 'User registered successfully'}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    user = User.query.filter_by(username=username).first()

    if user and check_password_hash(user.password, password):
        session['user_id'] = user.id
        if user.mfa_enabled:
            return jsonify({'message': 'MFA required', 'mfa_secret': user.mfa_secret}), 200
        return jsonify({'message': 'Login successful'}), 200

    return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    data = request.json
    otp = data.get('otp')
    user_id = session.get('user_id')
    user = User.query.get(user_id)

    if user and pyotp.TOTP(user.mfa_secret).verify(otp):
        return jsonify({'message': 'Access granted'}), 200

    return jsonify({'message': 'Invalid OTP'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    user = User.query.filter_by(username=username).first()

    if user and check_password_hash(user.password, password):
        return jsonify({'message': 'API access granted'}), 200

    return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=False)